class Solution(object):
    def climbStairs(self, n, costs):
        INF = 10 ** 18
        dp = [INF] * (n + 1)
        dp[0] = 0
        for i in range(1, n + 1):
            for jump in range(1, 4):
                if i - jump >= 0:
                    dp[i] = min(dp[i], dp[i - jump] + costs[i - 1] + jump * jump)
        return dp[n]
